#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, X; scanf("%d %d", &N, &X);
        int A[1005]; int B[1005];
        for(int i=0;i<N;i++) scanf("%d", &A[i]);
        for(int i=0;i<N;i++) scanf("%d", &B[i]);
        long long sum=0;
        for(int i=0;i<N;i++) if(A[i]>=X) sum+=B[i];
        printf("%lld\n", sum);
    }
    return 0;
}

