let idx = 0;
const T = input[idx++];
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = input[idx++];
  const X = input[idx++];
  const A = input.slice(idx, idx + N); idx += N;
  const B = input.slice(idx, idx + N); idx += N;
  let sum = 0;
  for (let i = 0; i < N; i++) {
    if (A[i] >= X) sum += B[i];
  }
  outputs.push(String(sum));
}
console.log(outputs.join('\n'));

